import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BZO4qERu.js";const b=JSON.parse('{"title":"騎砍2 | 純騎兵流終極指南：速度就是力量","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/cavalry-only.md","filePath":"bannerlord/cavalry-only.md"}'),i={name:"bannerlord/cavalry-only.md"};function o(n,t,h,d,s,c){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="騎砍2-純騎兵流終極指南-速度就是力量" tabindex="-1">騎砍2 | 純騎兵流終極指南：速度就是力量 <a class="header-anchor" href="#騎砍2-純騎兵流終極指南-速度就是力量" aria-label="Permalink to &quot;騎砍2 | 純騎兵流終極指南：速度就是力量&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>純騎兵流是騎砍2最爽的玩法——滿螢幕的騎兵衝鋒，敵軍瞬間蒸發。但養騎兵很貴、攻城很弱、在森林裡像靶子。這篇講清楚優劣和操作。</p><hr><h2 id="一、純騎兵流的優勢" tabindex="-1">一、純騎兵流的優勢 <a class="header-anchor" href="#一、純騎兵流的優勢" aria-label="Permalink to &quot;一、純騎兵流的優勢&quot;">​</a></h2><ul><li><strong>地圖移速最快</strong>：全騎兵 = 跑得比誰都快</li><li><strong>野戰碾壓</strong>：衝鋒一波帶走</li><li><strong>風箏無敵</strong>：弓騎兵邊跑邊射</li><li><strong>追擊逃兵最強</strong>：打完仗一個都跑不掉</li></ul><hr><h2 id="二、純騎兵流的劣勢" tabindex="-1">二、純騎兵流的劣勢 <a class="header-anchor" href="#二、純騎兵流的劣勢" aria-label="Permalink to &quot;二、純騎兵流的劣勢&quot;">​</a></h2><ul><li><strong>攻城極弱</strong>：騎兵不能上城牆</li><li><strong>森林地形廢掉</strong>：衝鋒速度 -50%</li><li><strong>養兵超貴</strong>：騎兵薪水是步兵的 2-3 倍</li><li><strong>對長矛陣沒轍</strong>：帝國軍團步兵擺好陣你就衝不過去</li></ul><hr><h2 id="三、最佳兵種配置" tabindex="-1">三、最佳兵種配置 <a class="header-anchor" href="#三、最佳兵種配置" aria-label="Permalink to &quot;三、最佳兵種配置&quot;">​</a></h2><h3 id="庫塞特體系-最強" tabindex="-1">庫塞特體系（最強） <a class="header-anchor" href="#庫塞特體系-最強" aria-label="Permalink to &quot;庫塞特體系（最強）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>兵種</th><th style="text-align:center;">佔比</th><th>用途</th></tr></thead><tbody><tr><td>庫塞特可汗親衛</td><td style="text-align:center;">50%</td><td>弓騎風箏，開場散開自由射擊</td></tr><tr><td>庫塞特重裝槍騎兵</td><td style="text-align:center;">30%</td><td>敵方陣型亂了之後衝鋒收割</td></tr><tr><td>帝國具裝騎兵</td><td style="text-align:center;">20%</td><td>坦度補強</td></tr></tbody></table><h3 id="帝國-瓦蘭迪亞體系" tabindex="-1">帝國 + 瓦蘭迪亞體系 <a class="header-anchor" href="#帝國-瓦蘭迪亞體系" aria-label="Permalink to &quot;帝國 + 瓦蘭迪亞體系&quot;">​</a></h3><table tabindex="0"><thead><tr><th>兵種</th><th style="text-align:center;">佔比</th></tr></thead><tbody><tr><td>瓦蘭迪亞騎士</td><td style="text-align:center;">40%</td></tr><tr><td>帝國具裝騎兵</td><td style="text-align:center;">40%</td></tr><tr><td>阿塞萊馬穆魯克</td><td style="text-align:center;">20%</td></tr></tbody></table><hr><h2 id="四、戰術操作" tabindex="-1">四、戰術操作 <a class="header-anchor" href="#四、戰術操作" aria-label="Permalink to &quot;四、戰術操作&quot;">​</a></h2><h3 id="_4-1-基本戰術" tabindex="-1">4.1 基本戰術 <a class="header-anchor" href="#_4-1-基本戰術" aria-label="Permalink to &quot;4.1 基本戰術&quot;">​</a></h3><ol><li>弓騎 F1+F4 散開 → F4 自由射擊</li><li>敵方追弓騎 → 陣型拉散</li><li>重騎兵 F1+F3 從側翼衝鋒</li><li>衝完立刻拉回來（F1+F2），不要留在敵陣裡</li></ol><h3 id="_4-2-衝鋒要點" tabindex="-1">4.2 衝鋒要點 <a class="header-anchor" href="#_4-2-衝鋒要點" aria-label="Permalink to &quot;4.2 衝鋒要點&quot;">​</a></h3><ul><li>永遠從<strong>側面或後面</strong>衝，不要正面衝</li><li>衝完立刻拉走，不要讓騎兵停下來跟步兵對砍</li><li>騎兵停下來 = 死騎兵</li><li>反覆衝鋒，不要一次衝完就不管</li></ul><hr><h2 id="五、攻城怎麼辦" tabindex="-1">五、攻城怎麼辦 <a class="header-anchor" href="#五、攻城怎麼辦" aria-label="Permalink to &quot;五、攻城怎麼辦&quot;">​</a></h2><p>純騎兵流攻城是硬傷。解法：</p><ol><li>戰時招募一些步兵專門攻城</li><li>讓盟友的步兵當攻城主力</li><li>圍城後不進攻，等對方餓到投降</li></ol><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./archer-only.html">騎砍2 | 純弓兵流終極指南</a></li><li><a href="./troop-tier-list.html">騎砍2 | 兵種大亂鬥</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',34)])])}const g=a(i,[["render",o]]);export{b as __pageData,g as default};
